async function main() {
  try {
    const formResult = await Input.formAsync('检查主键列是否重复', [
      {
        type: 'sheet',
        key: 'sheet',
        option: { label: '数据表', description: '请选择要操作的数据表' },
        required: true
      },
      {
        type: 'record',
        key: 'record',
        option: { label: '要检查的记录', description: '请选择要检查的记录', referenceSheet: 'sheet' },
        required: true
      }
    ]);

    const sheet = formResult.sheet;
    const record = formResult.record;

    const sheetFields = sheet.getFields();
    const primaryField = sheetFields.find(field => field.isPrimary());
    if (!primaryField) {
      Output.error('未找到主键字段，请确认有主键列');
      return;
    }
    const primaryValue = record.getCellValue(primaryField.getId());

    const resultFieldName = '重复标记';
    let resultField = sheet.getField(resultFieldName);
    if (!resultField) {
      resultField = sheet.insertField(resultFieldName, 'text');
    }
    const resultFieldId = resultField.getId();

    function compareCellValue(a, b) {
      if (a == null && b == null) return true;
      if (a == null || b == null) return false;
      if (typeof a === 'string' || typeof a === 'number' || typeof a === 'boolean') {
        return a === b;
      }
      if (typeof a === 'object' && typeof b === 'object') {
        if ('id' in a && 'id' in b) return a.id === b.id;
        if ('value' in a && 'value' in b) return a.value === b.value;
        if ('url' in a && 'url' in b) return a.url === b.url;
        if (Array.isArray(a) && Array.isArray(b)) {
          if (a.length !== b.length) return false;
          return a.every((item, idx) => compareCellValue(item, b[idx]));
        }
        return JSON.stringify(a) === JSON.stringify(b);
      }
      return false;
    }

    let isDuplicate = false;
    let hasMore = true;
    let cursor = '';
    while (hasMore && !isDuplicate) {
      const result = await sheet.getRecordsAsync({ pageSize: 100, cursor });
      for (const r of result.records) {
        if (r.getId() === record.getId()) continue;
        if (compareCellValue(r.getCellValue(primaryField.getId()), primaryValue)) {
          isDuplicate = true;
          break;
        }
      }
      hasMore = result.hasMore;
      cursor = result.cursor;
    }

    await sheet.updateRecordsAsync([{
      id: record.getId(),
      fields: { [resultFieldId]: isDuplicate ? '重复' : '不重复' }
    }]);

    Output.log(`检查完成，主键值${isDuplicate ? '有重复' : '不重复'}`);
  } catch (error) {
    Output.error(`执行过程中发生错误: ${error instanceof Error ? error.message : error}`);
  }
}

await main();
